import{_ as a,o as r,c as d,ai as e}from"./chunks/framework.SowO7O0D.js";const c=JSON.parse('{"title":"第六课：盘面基础知识","description":"","frontmatter":{},"headers":[],"relativePath":"guide/06-chart-basics.md","filePath":"guide/06-chart-basics.md","lastUpdated":0}'),s={name:"guide/06-chart-basics.md"};function n(l,t,i,o,h,b){return r(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="第六课-盘面基础知识" tabindex="-1">第六课：盘面基础知识 <a class="header-anchor" href="#第六课-盘面基础知识" aria-label="Permalink to “第六课：盘面基础知识”">​</a></h1><p>终于要看&quot;盘&quot;了！这一课教你读懂股票软件里的各种数字和图表。</p><h2 id="一、分时图" tabindex="-1">一、分时图 <a class="header-anchor" href="#一、分时图" aria-label="Permalink to “一、分时图”">​</a></h2><p>分时图是股票<strong>当天每分钟的走势线</strong>。</p><h3 id="怎么看" tabindex="-1">怎么看 <a class="header-anchor" href="#怎么看" aria-label="Permalink to “怎么看”">​</a></h3><ul><li><strong>黄线</strong>（加权平均线）：当天成交的平均价格</li><li><strong>白线</strong>（指数线）：大盘/个股的实时走势</li><li>黄线在白线上方 → 当天小盘股更强</li><li>白线在黄线上方 → 当天大盘股更强</li></ul><blockquote><p>💡 简单记忆：<strong>黄线是人，白线是市</strong>（个股看黄线，大盘看白线）</p></blockquote><h3 id="关键点位" tabindex="-1">关键点位 <a class="header-anchor" href="#关键点位" aria-label="Permalink to “关键点位”">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>含义</th></tr></thead><tbody><tr><td>昨收价</td><td>昨天收盘的价格</td></tr><tr><td>开盘价</td><td>今天9:30第一笔成交价格</td></tr><tr><td>最高价</td><td>当天最高成交价</td></tr><tr><td>最低价</td><td>当天最低成交价</td></tr><tr><td>现价</td><td>当前最新成交价</td></tr></tbody></table><h2 id="二、k线图-蜡烛图" tabindex="-1">二、K线图（蜡烛图） <a class="header-anchor" href="#二、k线图-蜡烛图" aria-label="Permalink to “二、K线图（蜡烛图）”">​</a></h2><p>K线图是<strong>记录股价走势最重要的工具</strong>，每个K线代表一段时间（1分钟/日/周/月）。</p><h3 id="k线怎么画" tabindex="-1">K线怎么画 <a class="header-anchor" href="#k线怎么画" aria-label="Permalink to “K线怎么画”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>       最高价</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>    开盘价│收盘价</span></span>
<span class="line"><span>    ─────┤</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>       最低价</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>阳线（红色/实心）</strong>：收盘价 &gt; 开盘价 = 涨 <strong>阴线（绿色/空心）</strong>：收盘价 &lt; 开盘价 = 跌</p><h3 id="k线的基本含义" tabindex="-1">K线的基本含义 <a class="header-anchor" href="#k线的基本含义" aria-label="Permalink to “K线的基本含义”">​</a></h3><table tabindex="0"><thead><tr><th>K线形态</th><th>含义</th></tr></thead><tbody><tr><td>大阳线（大涨）</td><td>多方强势，买方力量强</td></tr><tr><td>大阴线（大跌）</td><td>空方强势，卖方力量强</td></tr><tr><td>上影线很长</td><td>冲高回落，上方有压力</td></tr><tr><td>下影线很长</td><td>探底回升，下方有支撑</td></tr><tr><td>小阳/小阴线</td><td>多空平衡，观望为主</td></tr></tbody></table><blockquote><p>💡 <strong>上影线长</strong> = 涨上去被人打下来 = 压力 <strong>下影线长</strong> = 跌下去被人拉起来 = 支撑</p></blockquote><h2 id="三、成交量" tabindex="-1">三、成交量 <a class="header-anchor" href="#三、成交量" aria-label="Permalink to “三、成交量”">​</a></h2><p>成交量就是<strong>当天成交了多少股</strong>，用柱状图显示在K线下方。</p><h3 id="成交量的意义" tabindex="-1">成交量的意义 <a class="header-anchor" href="#成交量的意义" aria-label="Permalink to “成交量的意义”">​</a></h3><table tabindex="0"><thead><tr><th>现象</th><th>信号</th></tr></thead><tbody><tr><td>价涨量增</td><td>上涨有资金推动，健康</td></tr><tr><td>价涨量缩</td><td>上涨动力不足，小心</td></tr><tr><td>价跌量增</td><td>下跌有恐慌盘，谨慎</td></tr><tr><td>价跌量缩</td><td>下跌动能减弱，可能见底</td></tr></tbody></table><blockquote><p>💡 <strong>量和价是&quot;形影不离&quot;的好搭档</strong>，单独看价不靠谱，要结合量一起看。</p></blockquote><h2 id="四、股票软件常用功能" tabindex="-1">四、股票软件常用功能 <a class="header-anchor" href="#四、股票软件常用功能" aria-label="Permalink to “四、股票软件常用功能”">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>作用</th></tr></thead><tbody><tr><td>F10</td><td>看公司基本面（财务、股东、高管）</td></tr><tr><td>资金流向</td><td>看大单净流入/出</td></tr><tr><td>筹码分布</td><td>看持仓成本分布</td></tr><tr><td>公告</td><td>看公司最新公告</td></tr><tr><td>新闻</td><td>看公司相关新闻</td></tr></tbody></table><h2 id="五、盘口术语" tabindex="-1">五、盘口术语 <a class="header-anchor" href="#五、盘口术语" aria-label="Permalink to “五、盘口术语”">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>内盘</td><td>主动性卖出的成交量（绿色）</td></tr><tr><td>外盘</td><td>主动性买入的成交量（红色）</td></tr><tr><td>五档</td><td>买1-5、卖1-5的挂单</td></tr><tr><td>量比</td><td>今日成交量/过去5日均量，&gt;1放量</td></tr><tr><td>换手率</td><td>当天成交股数/总流通股</td></tr></tbody></table><blockquote><p>外盘 &gt; 内盘 = 买的人多 = 偏强</p></blockquote><h2 id="六、集合竞价看盘技巧" tabindex="-1">六、集合竞价看盘技巧 <a class="header-anchor" href="#六、集合竞价看盘技巧" aria-label="Permalink to “六、集合竞价看盘技巧”">​</a></h2><p>每天9:15-9:25是集合竞价时间：</p><ol><li>看开盘价是否大幅高开/低开（超过±5%要警惕）</li><li>看竞价时的成交量（量太大可能是诱多）</li><li>9:20前可以撤单，9:20后不能撤</li></ol><blockquote><p>🚨 9:15-9:20挂涨停价买入的人经常被&quot;钓鱼&quot;，庄家先拉高引你买入，9:20前撤单。</p></blockquote><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某股票今天收了一根&quot;大阳线&quot;，但成交量却比昨天萎缩了一半。这说明什么？应该怎么看？</p></blockquote><hr><p><strong>下一课预告</strong>：会看盘了还不够，下一课学习<strong>基本面分析</strong>——如何判断一家公司到底值多少钱。</p>`,35)])])}const u=a(s,[["render",n]]);export{c as __pageData,u as default};
